<?php
use CodeIgniter\Test\CIUnitTestCase;use Config\Database;
final class SalesGoalMigrationTest extends CIUnitTestCase
{
 public function testMigrationUpgradeConstraintsCrossYearAndRollback():void{require_once APPPATH.'Database/Migrations/2026-07-15-000002_CreateSalesGoalsAndProposalPayments.php';$db=db_connect();foreach(['propuesta_pago','meta_venta'] as $t)$db->query('DROP TABLE IF EXISTS '.$db->escapeIdentifiers($db->prefixTable($t)));$migration=new App\Database\Migrations\CreateSalesGoalsAndProposalPayments(Database::forge('tests'));$migration->up();$this->assertTrue($db->tableExists('meta_venta'));$this->assertTrue($db->tableExists('propuesta_pago'));$goal=['anio'=>2027,'mes'=>1,'usuario_id'=>3,'ucomercial_id'=>10,'asignado_por'=>2,'monto'=>'100.00','u_crea'=>2,'f_creacion'=>'2026-12-01 00:00:00'];$db->table('meta_venta')->insert($goal);$duplicateRejected=false;try{$db->table('meta_venta')->insert($goal);}catch(CodeIgniter\Database\Exceptions\DatabaseException){$duplicateRejected=true;}$this->assertTrue($duplicateRejected);$db->table('propuesta_pago')->insertBatch([['propuesta_id'=>1,'fecha_pago'=>'2026-12-01','monto'=>'40.00','secuencia'=>1,'u_crea'=>3,'f_creacion'=>'2026-01-01'],['propuesta_id'=>1,'fecha_pago'=>'2027-01-01','monto'=>'60.00','secuencia'=>2,'u_crea'=>3,'f_creacion'=>'2026-01-01']]);$this->assertSame(2,$db->table('propuesta_pago')->countAllResults());$migration->down();$this->assertFalse($db->tableExists('meta_venta'));$this->assertFalse($db->tableExists('propuesta_pago'));}
}
